const input = $input.first().json;
const body = input.body && typeof input.body === 'object' ? input.body : input;

function clean(value) {
  if (value === undefined || value === null) return '';
  return String(value).trim();
}

const messageId = clean(body.message_id);
const instructions = clean(body.reply_instructions);
const tone = clean(body.tone) || 'professional';

return [
  {
    json: {
      message_id: messageId,
      reply_instructions: instructions,
      tone,
      create_gmail_draft: body.create_gmail_draft !== false && body.create_gmail_draft !== 'false',
      send_email: false,
      source: clean(body.source) || 'n8n-email-draft-reply'
    }
  }
];

const source = $input.first().json;

function decodeBase64Url(data) {
  if (!data) return '';
  let normalized = String(data).replace(/-/g, '+').replace(/_/g, '/');
  while (normalized.length % 4) normalized += '=';
  return Buffer.from(normalized, 'base64').toString('utf8');
}

function getHeader(payload, name) {
  const headers = payload?.headers || [];
  const found = headers.find((header) => String(header.name).toLowerCase() === String(name).toLowerCase());
  return found ? found.value : '';
}

function collectBodyParts(part, out = { text: [], html: [] }) {
  if (!part) return out;

  const mimeType = part.mimeType || '';
  const data = part.body?.data;

  if (data && mimeType === 'text/plain') out.text.push(decodeBase64Url(data));
  if (data && mimeType === 'text/html') out.html.push(decodeBase64Url(data));

  for (const child of part.parts || []) collectBodyParts(child, out);
  return out;
}

const payload = source.payload || {};
const bodyParts = collectBodyParts(payload);
const body = bodyParts.text.join('\n\n').trim() || bodyParts.html.join('\n\n').trim();

const emailContext = {
  message_id: source.id,
  thread_id: source.threadId,
  subject: getHeader(payload, 'Subject'),
  from: getHeader(payload, 'From'),
  to: getHeader(payload, 'To'),
  cc: getHeader(payload, 'Cc'),
  date: getHeader(payload, 'Date'),
  message_id_header: getHeader(payload, 'Message-ID'),
  references: getHeader(payload, 'References'),
  in_reply_to: getHeader(payload, 'In-Reply-To'),
  snippet: source.snippet || '',
  body
};

const request = $('Normalize Draft Request').first().json;

const langgraphPayload = {
  model: 'onyx-fast',
  messages: [
    {
      role: 'system',
      content: 'You draft email replies. Use only the provided email context and user instructions. Return only the reply body. Do not claim the email was sent.'
    },
    {
      role: 'user',
      content: 'Email context:\n' + JSON.stringify(emailContext, null, 2) +
        '\n\nReply instructions:\n' + request.reply_instructions +
        '\n\nTone:\n' + request.tone
    }
  ],
  temperature: 0.2,
  max_tokens: 900,
  stream: false
};

return [
  {
    json: {
      ...request,
      email_context: emailContext,
      langgraph_payload: langgraphPayload
    }
  }
];

const current = $('Prepare LangGraph Request').first().json;
const llm = $input.first().json;

function extractAnswer(payload) {
  const choices = payload.choices || [];
  if (!choices.length) return '';
  const message = choices[0].message || {};
  return String(message.content || choices[0].text || '').trim();
}

function getEmailAddress(value) {
  const text = String(value || '');
  const match = text.match(/<([^>]+)>/);
  return (match ? match[1] : text).trim();
}

function base64Url(value) {
  return Buffer.from(value, 'utf8')
    .toString('base64')
    .replace(/\+/g, '-')
    .replace(/\//g, '_')
    .replace(/=+$/g, '');
}

const email = current.email_context;
const draftBody = extractAnswer(llm);
const to = getEmailAddress(email.from);
const subject = String(email.subject || '').toLowerCase().startsWith('re:')
  ? email.subject
  : 'Re: ' + (email.subject || '');

const headers = [
  `To: ${to}`,
  `Subject: ${subject}`,
  'Content-Type: text/plain; charset="UTF-8"',
  'MIME-Version: 1.0'
];

if (email.message_id_header) headers.push(`In-Reply-To: ${email.message_id_header}`);
if (email.references || email.message_id_header) {
  headers.push(`References: ${[email.references, email.message_id_header].filter(Boolean).join(' ')}`);
}

const raw = base64Url(headers.join('\r\n') + '\r\n\r\n' + draftBody);

return [
  {
    json: {
      draft_request: {
        message: {
          raw,
          threadId: email.thread_id
        }
      },
      message_id: email.message_id,
      thread_id: email.thread_id,
      subject,
      to,
      draft_body: draftBody,
      send_email: false,
      source: 'n8n-email-draft-reply'
    }
  }
];

const created = $input.first().json;
const draft = $('Build Gmail Draft Payload').first().json;

return [
  {
    json: {
      draft_created: Boolean(created.id),
      draft_id: created.id || null,
      message_id: draft.message_id,
      thread_id: draft.thread_id,
      subject: draft.subject,
      to: draft.to,
      draft_body: draft.draft_body,
      send_email: false,
      source: 'n8n-email-draft-reply'
    }
  }
];
